    const landGetter = buildMinGetter(landRides);

    let ans = Infinity;

    for (let i = 0; i < landRides.length; i++) {
        const finishLand = landStartTime[i] + landDuration[i];
        const timeForWater = query(waterGetter, finishLand);
        if (timeForWater < ans) {
            ans = timeForWater;
