    sortedRides: { start: number; duration: number; total: number; }[];
    prefixMinD: number[];
    suffixMinTotal: number[];
} {
    if (rides.length === 0) {
        return {
            sortedRides: [],
            prefixMinD: [],
            suffixMinTotal: []
        };
    }
    const sortedRides = rides.slice()
        .map(ride => ({ ...ride, total: ride.start + ride.duration }))
        .sort((a, b) => a.start - b.start);
    const n = sortedRides.length;
    const prefixMinD = new Array(n);
    const suffixMinTotal = new Array(n);

    prefixMinD[0] = sortedRides[0].duration;
    for (let i = 1; i < n; i++) {
        prefixMinD[i] = Math.min(prefixMinD[i - 1], sortedRides[i].duration);
    }

    suffixMinTotal[n - 1] = sortedRides[n - 1].total;
    for (let i = n - 2; i >= 0; i--) {
        suffixMinTotal[i] = Math.min(suffixMinTotal[i + 1], sortedRides[i].total);
    }

    return {
        sortedRides,
        prefixMinD,
        suffixMinTotal
    };
}

