    getter: {
        sortedRides: { start: number; duration: number; total: number; }[];
        prefixMinD: number[];
        suffixMinTotal: number[];
    },
    t: number
): number {
    const { sortedRides, prefixMinD, suffixMinTotal } = getter;
    const n = sortedRides.length;
    if (n === 0) {
        return Infinity;
    }

    let low = 0;
    let high = n - 1;
    let idx = -1;
    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (sortedRides[mid].start <= t) {
            idx = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    let candidate1 = Infinity;
    let candidate2 = Infinity;

    if (idx >= 0) {
        candidate1 = t + prefixMinD[idx];
    }

    if (idx + 1 < n) {
        candidate2 = suffixMinTotal[idx + 1];
    }

    return Math.min(candidate1, candidate2);
}
